example:
A Tests tab script validating a GET /users/1 response:

```javascript
pm.test("Status code is 200", function () {
    pm.response.to.have.status(200);
});

pm.test("Response time is under 500ms", function () {
    pm.expect(pm.response.responseTime).to.be.below(500);
});

pm.test("User id is 1 and email exists", function () {
    const body = pm.response.json();
    pm.expect(body.id).to.eql(1);
    pm.expect(body.email).to.be.a('string').and.not.empty;
});
```

With the URL set to {{base_url}}/users/1 and base_url defined in the environment, this runs three checks automatically on every Send.

